 private boolean ifCreateNewMenuSet(JspWriter out, MenuConfiguration mc, String newMenuSetName, MenuLog menuLog) throws JSONException, IOException {
    if(newMenuSetName!=null){
        JSONObject messageJo =  new JSONObject();
        MenuSet addedMenuSet = mc.addMenuSet(newMenuSetName);

        if(addedMenuSet!=null){
            mc.save();

            //用builder模式, 未來屬性擴充實方便延用
            MenuSetCreateAction createAction = MenuSetCreateAction.getBuilder(menuLog, newMenuSetName).build();
            menuLog.genMenuSetLog(createAction, createAction.getCreateMenuSetInfo());

            messageJo.put("updateMenuSetId", mc.getMenuSets().size()-1);
            out.print(messageJo.toString());
        }
        else{
            messageJo.put("msg","Duplicated menu set name.");
            out.print(messageJo.toString());
        }

        return true;
    }

    return false;
 }




