    User user = (User)session.getAttribute("USER");
    String apname = request.getParameter("a");

    Log log = new Log("log/menuSet.log").setIfDisplayTime(true);
    MenuLog menuLog = new MenuLog(log, apname, user.getUserId());

    if(user==null || !user.ifApManager(apname)) return;

    JSONObject jo = new JSONObject();
    MenuConfiguration mc= Account.getInstance(apname).getMenuConfiguration();

    String newMenuSetName=request.getParameter("newMenuSetName");
    if (ifCreateNewMenuSet(out, mc, newMenuSetName, menuLog)) return;

    int deleteMenuSetId=Encoder.parseInt(request.getParameter("dmsi"),-1);
    if (ifDeleteMenuSet(out, mc, deleteMenuSetId, menuLog)) return;

    int updateMenuSetId= Encoder.parseInt(request.getParameter("umsi"),-1);
    if(updateMenuSetId>=0){
        String menuSetPaths=request.getParameter("paths");
        Collection<MenuTab> moveToDefaultMenuTabs = new ConcurrentLinkedQueue<>();
        Collection<MenuTab> moveToUpdateMenuTabs = new ConcurrentLinkedQueue<>();

        if(menuSetPaths!=null){
            JSONArray ja=new JSONArray(menuSetPaths);
            Set<String> paths=new LinkedHashSet<>();
            for(int i=0;i<ja.length();i++){
              paths.add(ja.optString(i));
            }

            mc.updateMenuSet(updateMenuSetId, paths, moveToDefaultMenuTabs, moveToUpdateMenuTabs, jo , menuLog);
            mc.save();
       }

        String editMenuSetName = request.getParameter("editMenuSetName");
        if(!Encoder.isEmptyOrWhitespaceOnly(editMenuSetName)){
            MenuSet updateMenuSet = mc.getMenuSet(updateMenuSetId);

            if(updateMenuSet != null){
               updateMenuSet.setName(editMenuSetName);
               mc.save();
            }
        }

        boolean uploadBanner=request.getParameter("uploadBanner")!=null;
        boolean uploadLogo=request.getParameter("uploadLogo")!=null;
        if(uploadBanner || uploadLogo){
            FileRenamePolicy policy = new DefaultFileRenamePolicy();//no adding xxx@ hash for these files so that they don't need to be checked for access right
            try{
                SIMSMultipartRequest mreq=new SIMSMultipartRequest(request, "cust/data/"+apname+"/upload",1024 * 1024 * 1024, "UTF-8", policy);
                Collection<UploadedFile> files=mreq.getFile("upload");
                MenuSet menuSet=mc.getMenuSet(updateMenuSetId);
                for (UploadedFile file : files) {
                    if(uploadBanner){
                        menuSet.setBanner(file.getFilesystemName());
                    }
                    else if(uploadLogo){
                        menuSet.setLogoIcon(file.getFilesystemName());
                    }
                }
                menuSet.save();
            }catch (Exception e){
                ExceptionManager.getInstance().processException(e);
            }
        }

        boolean removeBanner=request.getParameter("removeBanner")!=null;
        boolean removeLogo=request.getParameter("removeLogo")!=null;
        if(removeLogo || removeBanner){
            MenuSet menuSet=mc.getMenuSet(updateMenuSetId);
            if(removeBanner) {
                menuSet.setBanner(null);
                Account.getInstance(apname).getAppSetting().removeBanner(user,bundle);
            }
            if(removeLogo) {
                menuSet.setLogoIcon(null);
                if(updateMenuSetId==MenuSet.DEFAULT_MENUSET){
                    Account.getInstance(apname).getAppSetting().removeLogo(user,bundle);
                }
            }
            menuSet.save();
        }
            jo.put("updateMenuSetId",updateMenuSetId);
    }

